[Form]
public class FWFTextBlockValue extends FormRun
{
    Common              callerRecord;
    FormRun callerFormObject;

    FWFTextBlockModule  module;
    FWFTextBlockModule  moduleCustVend;
    FWFTextBlockModule  oldModuleCustVend;
    str                 oldText;

    int                 selectedTab;
    LanguageId          languageId;

    #define.CurrentVersion(1)
    #localmacro.CurrentList
        selectedTab
    #endmacro


}

public void close()
{
    selectedTab = TextEditTab.tab();

    xSysLastValue::saveLast(this);

    super();

    //FormRun callerFormObject = element.args().caller() as FormRun;
    if (callerFormObject && formHasMethod(callerFormObject, identifierStr(fwfTextBlockInstanceFormClosed)))
    {
        /// Refreshes the purchTable_ds of PurchTable form resp. the salesAgreementHeader_ds of SalesAgreement form resp. the purchAgreementHeader_ds of PurchAgreement form
        callerFormObject.fwfTextBlockInstanceFormClosed();
    }
}

void init()
{
    Common	common = this.args().record();

    if (common.TableId == tableNum(PurchLineAllVersions))
    {
        PurchLineAllVersions	purchLineAllVersions = common as PurchLineAllVersions;
        if (purchLineAllVersions.IsArchived)	// if already archived, the textblocks are referenced to the PurchLineHistory
        {
            PurchLineHistory	purchLineHistory = PurchLineHistory::findRecId(purchLineAllVersions.RecId);
            this.args().record(purchLineHistory);
        }
    }

    if (common.TableId == tableNum(AgreementLineHistory))
    {
        AgreementLineHistory	agreementLineHistory = common as AgreementLineHistory;
        if (agreementLineHistory.InstanceRelationType  == tableNum(AgreementLineQuantityCommitmentHistory))
        {
            AgreementLineQuantityCommitmentHistory agreementLineQuantityCommitmentHistory = common as AgreementLineQuantityCommitmentHistory;
            this.args().record(agreementLineQuantityCommitmentHistory);
        }
        else if (agreementLineHistory.InstanceRelationType  == tableNum(AgreementLineVolumeCommitmentHistory))
        {
            AgreementLineVolumeCommitmentHistory agreementLineVolumeCommitmentHistory = common as AgreementLineVolumeCommitmentHistory;
            this.args().record(agreementLineVolumeCommitmentHistory);
        }
    }

    super();

    if (! element.args().dataset())
    {
        throw error(Error::missingRecord(this.name()));
    }


    xSysLastValue::getLast(this);
    TextEditTab.tab(selectedTab);
}

public void initFromCaller()
{
    boolean allowCreate;

    callerRecord = element.args().record();
    callerFormObject = element.args().caller() as FormRun;

    SysQuery::findOrCreateRange(FWFTextBlockInstance_ds.query().dataSourceTable(tableNum(FWFTextBlockInstance)),
                               fieldNum(FWFTextBlockInstance, RefTableId)).value(queryValue(callerRecord.tableId));
    SysQuery::findOrCreateRange(FWFTextBlockInstance_ds.query().dataSourceTable(tableNum(FWFTextBlockInstance)),
                               fieldNum(FWFTextBlockInstance, RefRecId)).value(queryValue(callerRecord.RecId));

    switch (callerRecord.TableId)
    {
        case tableNum(SalesTable) :
        case tableNum(SalesAgreementHeader) :
            module          = FWFTextBlockModule::Customer;
            moduleCustVend  = FWFTextBlockModule::Customer;
            allowCreate     = true;
            break;

        case tableNum(SalesLine) :
            module          = FWFTextBlockModule::ReleasedProduct;
            moduleCustVend  = FWFTextBlockModule::Customer;
            allowCreate     = true;
            break;

        case tableNum(PurchLine) :
            module          = FWFTextBlockModule::ReleasedProduct;
            moduleCustVend  = FWFTextBlockModule::Supplier;
            allowCreate     = true;
            break;

        case tableNum(PurchTable) :
        case tableNum(PurchAgreementHeader):
            module          = FWFTextBlockModule::Supplier;
            moduleCustVend  = FWFTextBlockModule::Supplier;
            allowCreate     = true;
            break;

        case tableNum(CustInvoiceTable) :
            module = FWFTextBlockModule::Customer;
            moduleCustVend = FWFTextBlockModule::Customer;
            allowCreate = true;
            break;

        case tableNum(AgreementLine) :
            module = FWFTextBlockModule::ReleasedProduct;
            allowCreate = true;

            AgreementLine agreementLine = callerRecord as AgreementLine;
            if (agreementLine.purchAgreementHeader())
            {
                moduleCustVend  = FWFTextBlockModule::Supplier;
            }
            else if (agreementLine.salesAgreementHeader())
            {
                moduleCustVend  = FWFTextBlockModule::Customer;
            }
            break;

        case tableNum(AgreementLineVolumeCommitmentHistory) :
            module = FWFTextBlockModule::ReleasedProduct;
            allowCreate = false;

            AgreementLineVolumeCommitmentHistory agreementLineVolumeCommitmentHistory = callerRecord as AgreementLineVolumeCommitmentHistory;
            AgreementLine agreementLineVolume = AgreementLine::find(agreementLineVolumeCommitmentHistory.AgreementLine);
            if (agreementLineVolume.purchAgreementHeader())
            {
                moduleCustVend  = FWFTextBlockModule::Supplier;
            }
            else if (agreementLineVolume.salesAgreementHeader())
            {
                moduleCustVend  = FWFTextBlockModule::Customer;
            }
            break;

        case tableNum(AgreementLineQuantityCommitmentHistory) :
            module = FWFTextBlockModule::ReleasedProduct;
            allowCreate = false;

            AgreementLineQuantityCommitmentHistory agreementLineQuantityCommitmentHistory = callerRecord as AgreementLineQuantityCommitmentHistory;
            AgreementLine agreementLineQuantity = AgreementLine::find(agreementLineQuantityCommitmentHistory.AgreementLine);
            if (agreementLineQuantity.purchAgreementHeader())
            {
                moduleCustVend  = FWFTextBlockModule::Supplier;
            }
            else if (agreementLineQuantity.salesAgreementHeader())
            {
                moduleCustVend  = FWFTextBlockModule::Customer;
            }
            break;

        case tableNum(ProdTable) :
        case tableNum(ReqPO) :
            module			= FWFTextBlockModule::ReleasedProduct;
            moduleCustVend	= FWFTextBlockModule::ReleasedProduct;
            allowCreate     = true;
            break;

        case tableNum(BOM) :
        case tableNum(ProdBOM) :
            module = FWFTextBlockModule::ReleasedProduct;
            moduleCustVend = FWFTextBlockModule::ReleasedProduct;
            allowCreate = true;
            break;

        case tableNum(ProjInvoiceJour) :
            module = FWFTextBlockModule::Project;
            moduleCustVend = FWFTextBlockModule::Project;
            allowCreate = false;
            break;

        case tableNum(ProjInvoiceItem) :
            module = FWFTextBlockModule::ReleasedProduct;
            moduleCustVend = FWFTextBlockModule::Project;
            allowCreate = false;
            break;

        case tableNum(ProjProposalJour) :
            module = FWFTextBlockModule::Project;
            moduleCustVend = FWFTextBlockModule::Project;
            ProjProposalJour projProposalJour = callerRecord as ProjProposalJour;
            if (projProposalJour.LineProperty != ProjLinePropertyCode::Invoiced)
            {
                allowCreate = true;
            }
            break;

        case tableNum(ProjProposalItem) :
            module = FWFTextBlockModule::ReleasedProduct;
            moduleCustVend = FWFTextBlockModule::Project;
            ProjProposalItem projProposalItem = callerRecord as ProjProposalItem;
            if (projProposalItem.projProposalJour().LineProperty != ProjLinePropertyCode::Invoiced)
            {
                allowCreate = true;
            }
            break;

        case tableNum(SalesQuotationTable) :
            SalesQuotationTable salesQuotationTable = callerRecord as SalesQuotationTable;
            module          = salesQuotationTable.QuotationType == QuotationType::Sales ? FWFTextBlockModule::Customer : FWFTextBlockModule::Project;
            moduleCustVend  = salesQuotationTable.QuotationType == QuotationType::Sales ? FWFTextBlockModule::Customer : FWFTextBlockModule::Project;
            allowCreate     = true;
            break;

        case tableNum(SalesQuotationLine) :
            SalesQuotationLine salesQuotationLine = callerRecord as SalesQuotationLine;
            module          = FWFTextBlockModule::ReleasedProduct;
            moduleCustVend  = salesQuotationLine.salesQuotationTable().QuotationType == QuotationType::Sales ? FWFTextBlockModule::Customer : FWFTextBlockModule::Project;
            allowCreate     = true;
            break;

        case tableNum(InventTransferJour) :
            InventTransferJour inventTransferJour = callerRecord as InventTransferJour;
            module          = FWFTextBlockModule::TransferOrder;
            moduleCustVend  = FWFTextBlockModule::TransferOrder;
            allowCreate     = true;
            break;

        case tableNum(PurchRFQCaseTable) :
            PurchRFQCaseTable RFQCaseTable = callerRecord as PurchRFQCaseTable;
            module          = FWFTextBlockModule::Supplier;
            moduleCustVend  = FWFTextBlockModule::Supplier;
            allowCreate     = true;
            break;

        case tableNum(PurchRFQCaseLine) :
            PurchRFQCaseLine RFQCaseLine = callerRecord as PurchRFQCaseLine;
            module          = FWFTextBlockModule::ReleasedProduct;
            moduleCustVend  = FWFTextBlockModule::Supplier;
            allowCreate     = true;
            break;

        case tableNum(PurchReqTable) :
            PurchReqTable reqTable = callerRecord as PurchReqTable;
            module          = FWFTextBlockModule::Supplier;
            moduleCustVend  = FWFTextBlockModule::Supplier;
            allowCreate     = true;
            break;

        case tableNum(PurchReqLine) :
            PurchReqLine reqLine = callerRecord as PurchReqLine;
            module          = FWFTextBlockModule::ReleasedProduct;
            moduleCustVend  = FWFTextBlockModule::Supplier;
            allowCreate     = true;
            break;

        case tableNum(PurchRFQReplyTable) :
            PurchRFQReplyTable RFQReplyTable = callerRecord as PurchRFQReplyTable;
            module          = FWFTextBlockModule::Supplier;
            moduleCustVend  = FWFTextBlockModule::Supplier;
            allowCreate     = true;
            break;

        case tableNum(PurchRFQReplyLine) :
            PurchRFQReplyLine RFQReplyLine = callerRecord as PurchRFQReplyLine;
            module          = FWFTextBlockModule::ReleasedProduct;
            moduleCustVend  = FWFTextBlockModule::Supplier;
            allowCreate     = true;
            break;
    }

    switch (callerRecord.TableId)
    {
        case tableNum(SalesLine) :
            SalesLine salesLine = callerRecord as SalesLine;
            languageId = salesLine.salesTable().LanguageId;
            break;

        case tableNum(SalesQuotationLine) :
            SalesQuotationLine salesQuotationLine = callerRecord as SalesQuotationLine;
            languageId = salesQuotationLine.salesQuotationTable().LanguageId;
            break;

        case tableNum(PurchLine) :
            PurchLine purchLine = callerRecord as PurchLine;
            languageId = purchLine.purchTable().LanguageId;
            break;

        case tableNum(AgreementLine) :
            AgreementLine agreementLine = callerRecord as AgreementLine;
            languageId = agreementLine.agreementHeader().Language;
            break;

        case tableNum(SalesAgreementHeader) :
            SalesAgreementHeader salesAgreementHeader = callerRecord as SalesAgreementHeader;
            languageId = salesAgreementHeader.Language;
            break;

        case tableNum(PurchAgreementHeader) :
            PurchAgreementHeader purchAgreementHeader = callerRecord as PurchAgreementHeader;
            languageId = purchAgreementHeader.Language;
            break;

        default :
            FieldId langFieldId = fieldName2id(callerRecord.TableId, identifierStr(LanguageId));
            if (langFieldId)
            {
                languageId = callerRecord.(langFieldId);
            }
            break;
    }

    FWFTextBlockInstance_ds.allowCreate(allowCreate);
    FWFTextBlockInstance_ds.allowEdit(allowCreate);
    FWFTextBlockInstance_ds.allowDelete(allowCreate);
    FWFTextBlockTransParm_ds.allowCreate(allowCreate);
    FWFTextBlockTransParm_ds.allowEdit(allowCreate);
    FWFTextBlockTransParm_ds.allowDelete(allowCreate);

    this.updateDesign();

}

