public container pack()
{
    return [#CurrentVersion,#CurrentList];
}

public boolean unpack(container packedClass)
{
    Integer     version     = conpeek(packedClass,1);

    switch (version)
    {
        case #CurrentVersion:
            [version,#CurrentList] = packedClass;
            break;
        default:
            return false;
    }

    return true;
}

void updateDesign()
{
    AgreementLine agreementLine;
    SalesAgreementHeader salesAgreementHeader;
    PurchAgreementHeader purchAgreementHeader;

    if (element.args().dataset() == tableNum(AgreementLine))
    {
        agreementLine = callerRecord as AgreementLine;
        salesAgreementHeader = agreementLine.salesAgreementHeader();
        purchAgreementHeader = agreementLine.purchAgreementHeader();
    }

    TextTabPage.allowEdit(FWFTextBlockInstance.RecId);

    if (HTML)
    {
        HTML.parmHtml(FWFTextBlockValue::find(FWFTextBlockInstance.ValueRecId).htmlText());
    }

    if (moduleCustVend || ! oldModuleCustVend)
    {
        switch (moduleCustVend)
        {
            case FWFTextBlockModule::Supplier :
                PrintOnSalesFormLetters.visible(false);
                PrintOnPurchFormLetters.visible(true);
                PrintOnProductionReports.visible(false);
                PrintOnProjectReports.visible(false);
                PrintOnInventoryReports.visible(false);
                break;

            case FWFTextBlockModule::Customer :
                PrintOnSalesFormLetters.visible(true);
                PrintOnPurchFormLetters.visible(module == FWFTextBlockModule::ReleasedProduct ||
                                               (module == FWFTextBlockModule::Customer && callerRecord.TableId == tableNum(SalesTable)));
                PrintOnProductionReports.visible(module == FWFTextBlockModule::ReleasedProduct);
                PrintOnProjectReports.visible(true);
                PrintOnInventoryReports.visible(false);
                FWFTextBlockTransParm_ds.object(fieldNum(FWFTextBlockTransParm, PrintOnSalesQuotation))
                    .visible(element.args().dataset() == tableNum(SalesQuotationTable) ||
                             element.args().dataset() == tableNum(SalesQuotationLine));
                FWFTextBlockTransParm_ds.object(fieldNum(FWFTextBlockTransParm, PrintOnSalesConfirmation)).visible(element.args().dataset() != tableNum(CustInvoiceTable));
                FWFTextBlockTransParm_ds.object(fieldNum(FWFTextBlockTransParm, PrintOnSalesPickingList)).visible(element.args().dataset() != tableNum(CustInvoiceTable));
                FWFTextBlockTransParm_ds.object(fieldNum(FWFTextBlockTransParm, PrintOnSalesPackingSlip)).visible(element.args().dataset() != tableNum(CustInvoiceTable));
                FWFTextBlockTransParm_ds.object(fieldNum(FWFTextBlockTransParm, PrintOnSalesInvoice)).visible(element.args().dataset() != tableNum(CustInvoiceTable));
                FWFTextBlockTransParm_ds.object(fieldNum(FWFTextBlockTransParm, PrintOnCustFreeInvoice)).visible(element.args().dataset() == tableNum(CustInvoiceTable));
                FWFTextBlockTransParm_ds.object(fieldNum(FWFTextBlockTransParm, PrintOnSalesAgreement)).visible(element.args().dataset() == tableNum(SalesAgreementHeader) || salesAgreementHeader.RecId);
                break;

            case FWFTextBlockModule::ReleasedProduct :
                switch (callerRecord.TableId)
                {
                    case tableNum(ProdTable) :
                        PrintOnProductionReports.visible(true);
                        PrintOnSalesFormLetters.visible(false);
                        PrintOnPurchFormLetters.visible(false);
                        PrintOnProjectReports.visible(false);
                        PrintOnInventoryReports.visible(false);
                        break;

                    case tableNum(ReqPO) :
                        ReqPO reqPO = callerRecord as ReqPO;
                        switch (reqPO.RefType)
                        {
                            case ReqRefType::ItemPlannedOrder :
                                PrintOnProductionReports.visible(false);
                                PrintOnSalesFormLetters.visible(false);
                                PrintOnPurchFormLetters.visible(true);
                                PrintOnProjectReports.visible(false);
                                PrintOnInventoryReports.visible(false);
                                break;

                            case ReqRefType::BOMPlannedOrder :
                                PrintOnProductionReports.visible(true);
                                PrintOnSalesFormLetters.visible(false);
                                PrintOnPurchFormLetters.visible(false);
                                PrintOnProjectReports.visible(false);
                                PrintOnInventoryReports.visible(false);
                                break;

                            default :
                                PrintOnProductionReports.visible(true);
                                PrintOnSalesFormLetters.visible(false);
                                PrintOnPurchFormLetters.visible(true);
                                PrintOnProjectReports.visible(false);
                                PrintOnInventoryReports.visible(false);
                                break;
                        }

                    case tableNum(ProdBOM) :
                    case tableNum(BOM) :
                        PrintOnProductionReports.visible(true);
                        PrintOnSalesFormLetters.visible(false);
                        PrintOnPurchFormLetters.visible(true);
                        PrintOnProjectReports.visible(false);
                        PrintOnInventoryReports.visible(false);
                        break;

                    case tableNum(ProjTable) :
                        PrintOnProductionReports.visible(false);
                        PrintOnSalesFormLetters.visible(false);
                        PrintOnPurchFormLetters.visible(false);
                        PrintOnProjectReports.visible(true);
                        PrintOnInventoryReports.visible(false);
                        break;
                }
                break;

            case FWFTextBlockModule::Project :
                PrintOnProductionReports.visible(false);
                PrintOnSalesFormLetters.visible(true);
                PrintOnPurchFormLetters.visible(false);
                PrintOnProjectReports.visible(true);
                PrintOnInventoryReports.visible(false);
                break;

            case FWFTextBlockModule::TransferOrder :
                PrintOnProductionReports.visible(false);
                PrintOnSalesFormLetters.visible(false);
                PrintOnPurchFormLetters.visible(false);
                PrintOnProjectReports.visible(false);
                PrintOnInventoryReports.visible(true);
                ICTabPage.visible(false);
                break;
        }
    }

    // parameter 'showWarning' is only relevant in case of general setup (FWFTextBlockUsage)
    FWFTextBlockTransParm_ds.object(fieldNum(FWFTextBlockTransParm, ShowWarning)).visible(false);

    oldModuleCustVend = moduleCustVend;
}

public void setTextBlockValueFromSetup()
{
    FWFTextBlockTable       textBlockTable;
    FWFTextBlockLanguage    textBlockLanguage;
    str                     text;

    textBlockTable    = FWFTextBlockTable::findNameModule(FWFTextBlockTransParm.Name, module);
    if (textBlockTable.RecId)
    {
        FWFTextBlockTransParm.initFromSetupParm(FWFTextBlockTableParm::find(textBlockTable.SetupRefRecId));
    }

    textBlockLanguage = FWFTextBlockLanguage::find(textBlockTable.RecId, FWFTextBlockTransParm.LanguageId);
    if (textBlockLanguage)
    {
        text = textBlockLanguage.editValue();
    }
    FWFTextBlockInstance.editValue(true, text);

    FWFTextBlockTransParm_ds.refresh();
    FWFTextBlockInstance_ds.refresh();
}

