void clicked()
{
    container   textLines;
    str         textLine;
    Int         i;

    super();

    if (! callerRecord || ! FWFTextBlockInstance)
    {
        return;
    }

    textLines = str2con(FWFTextBlockValueSubstitutor::newParameters(
                        callerRecord, null, FWFTextBlockInstance.plainText()).run(), '\n');

    for (i=1; i<=conLen(textLines); i++)
    {
        textLine = conPeek(textLines, i);
        if (textLine)
        {
            info(textLine);
        }
    }
}

public void lostFocus()
{
    super();

    if (FWFTextBlockTransParm.LanguageId && FWFTextBlockTransParm.Name && ! FWFTextBlockTransParm.RecId)
    {
        if (FWFTextBlockInstance_ds.validateWrite())
        {
            FWFTextBlockInstance_ds.write();
        }
    }
}

/// <summary>
/// Open the <c>FWFTextBlockTableHTML</c> form to edit the text in HTML format.
/// </summary>
public void clicked()
{
    super();

    FormRun formRun;
    Args args = new Args();

    args.caller(this);
    args.name(formstr(FWFTextBlockTableHTML));
    args.record(FWFTextBlockInstance);

    // Initialize editor form, run and wait
    formRun = ClassFactory.formRunClass(args);
    formRun.init();
    formRun.run();
    formRun.wait();

    // Refresh FWFTextBlockInstance datasource
    FWFTextBlockInstance_ds.research(true);
}

public void pageActivated()
{
    element.updateDesign();

    super();
}
